<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  :root {
    --bg: #14161a;
    --panel: #1e2128;
    --border: #2c313c;
    --text: #d7dae0;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: radial-gradient(1200px 800px at 50% -10%, #1b1f27, var(--bg));
    color: var(--text);
    font-family: "Segoe UI", system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 20px;
    font-weight: 600;
    letter-spacing: 0.5px;
    color: #aeb4bf;
  }
  #toolbar {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
  }
  #toolbar button {
    appearance: none;
    border: 1px solid var(--border);
    background: var(--panel);
    color: var(--text);
    padding: 8px 16px;
    border-radius: 8px;
    font-size: 14px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: background .12s, border-color .12s, transform .05s;
  }
  #toolbar button:hover { background: #262b34; }
  #toolbar button:active { transform: scale(0.97); }
  #toolbar button .swatch {
    width: 12px;
    height: 12px;
    border-radius: 3px;
    display: inline-block;
  }
  #toolbar button.active {
    border-color: #6ea8ff;
    background: #253044;
    box-shadow: 0 0 0 1px #6ea8ff inset;
  }
  #mat-sand .swatch  { background: #e0b45a; }
  #mat-water .swatch { background: #3f8fd8; }
  #mat-wall .swatch  { background: #8a8f99; }
  #mat-acid .swatch  { background: #7ee83a; }
  #mat-empty .swatch { background: #14161a; border: 1px solid #444; }
  #clear {
    border-color: #5a3a3a !important;
  }
  #clear:hover { background: #3a2626 !important; }
  #sand {
    width: 500px;
    height: 500px;
    max-width: 92vw;
    max-height: 92vw;
    image-rendering: pixelated;
    border: 1px solid var(--border);
    border-radius: 10px;
    background: #0c0e11;
    box-shadow: 0 8px 30px rgba(0,0,0,0.45);
    cursor: crosshair;
    touch-action: none;
  }
  .hint { font-size: 12px; color: #6b7280; margin: 0; }
</style>
</head>
<body>
  <h1>Falling Sand</h1>
  <div id="toolbar">
    <button id="mat-sand" class="active"><span class="swatch"></span>Sand</button>
    <button id="mat-water"><span class="swatch"></span>Water</button>
    <button id="mat-wall"><span class="swatch"></span>Wall</button>
    <button id="mat-acid"><span class="swatch"></span>Acid</button>
    <button id="mat-empty"><span class="swatch"></span>Erase</button>
    <button id="clear">✕ Clear</button>
  </div>
  <canvas id="sand" width="100" height="100"></canvas>
  <p class="hint">Drag on the canvas to paint the selected material.</p>

<script>
(function () {
  "use strict";

  var W = 100, H = 100;
  var EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  var NAMES = ["empty", "sand", "water", "wall", "acid"];
  var IDS = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };

  var grid = new Uint8Array(W * H);
  var moved = new Uint8Array(W * H);

  // Deterministic PRNG so tick(n) behaves reproducibly.
  var seed = 0x9e3779b9;
  function rnd() {
    seed = (Math.imul(seed, 1664525) + 1013904223) >>> 0;
    return seed / 4294967296;
  }

  // Static per-cell shade noise for visual texture (fixed at init, cosmetic only).
  var shade = new Uint8Array(W * H);
  (function () {
    var s = 12345;
    for (var i = 0; i < shade.length; i++) {
      s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
      shade[i] = s % 28;
    }
  })();

  function inB(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }
  function at(x, y) { return y * W + x; }

  function isLiquid(m) { return m === WATER || m === ACID; }

  // --- Sand: fall, sink through liquid (liquid escapes sideways), slide diagonally.
  function updateSand(x, y) {
    var i = at(x, y);
    if (y + 1 < H) {
      var b = at(x, y + 1);
      var bm = grid[b];
      if (bm === EMPTY) {
        grid[b] = SAND; grid[i] = EMPTY; moved[b] = 1;
        return;
      }
      if (isLiquid(bm)) {
        // Displace the liquid sideways/locally so it escapes AROUND
        // the incoming sand instead of riding up the column.
        var d = rnd() < 0.5 ? 1 : -1;
        var spot = -1;
        var dd, nx, k;
        // Prefer slots beside the liquid cell, then beside the sand cell.
        var cand = [
          [x + d, y + 1], [x - d, y + 1],
          [x + d, y],     [x - d, y]
        ];
        for (k = 0; k < cand.length; k++) {
          nx = cand[k][0];
          var ny = cand[k][1];
          if (inB(nx, ny) && grid[at(nx, ny)] === EMPTY) { spot = at(nx, ny); break; }
        }
        if (spot !== -1) {
          grid[spot] = bm; moved[spot] = 1;
          grid[b] = SAND;  moved[b] = 1;
          grid[i] = EMPTY;
        } else {
          // Fully enclosed: plain swap (one cell per step; the moved
          // flag stops the same liquid being pushed again this step).
          grid[b] = SAND; grid[i] = bm;
          moved[b] = 1; moved[i] = 1;
        }
        return;
      }
      // Blocked below by solid: slide diagonally, random side first.
      var dir = rnd() < 0.5 ? 1 : -1;
      var sides = [dir, -dir];
      for (var s2 = 0; s2 < 2; s2++) {
        nx = x + sides[s2];
        if (inB(nx, y + 1) && grid[at(nx, y + 1)] === EMPTY) {
          grid[at(nx, y + 1)] = SAND; moved[at(nx, y + 1)] = 1;
          grid[i] = EMPTY;
          return;
        }
      }
    }
    // rest
  }

  // --- Liquid movement shared by water and acid.
  function moveLiquid(x, y, m) {
    var i = at(x, y);
    if (y + 1 < H && grid[at(x, y + 1)] === EMPTY) {
      grid[at(x, y + 1)] = m; moved[at(x, y + 1)] = 1;
      grid[i] = EMPTY;
      return;
    }
    var dir = rnd() < 0.5 ? 1 : -1;
    var sides = [dir, -dir], k, nx;
    if (y + 1 < H) {
      for (k = 0; k < 2; k++) {
        nx = x + sides[k];
        if (inB(nx, y + 1) && grid[at(nx, y + 1)] === EMPTY) {
          grid[at(nx, y + 1)] = m; moved[at(nx, y + 1)] = 1;
          grid[i] = EMPTY;
          return;
        }
      }
    }
    for (k = 0; k < 2; k++) {
      nx = x + sides[k];
      if (inB(nx, y) && grid[at(nx, y)] === EMPTY) {
        grid[at(nx, y)] = m; moved[at(nx, y)] = 1;
        grid[i] = EMPTY;
        return;
      }
    }
  }

  function updateAcid(x, y) {
    var i = at(x, y);
    // Dissolve sand/wall below or beside.
    var targets = [[x, y + 1], [x - 1, y], [x + 1, y]];
    for (var k = 0; k < 3; k++) {
      var tx = targets[k][0], ty = targets[k][1];
      if (!inB(tx, ty)) continue;
      var tm = grid[at(tx, ty)];
      if (tm === SAND || tm === WALL) {
        if (rnd() < 0.45) {
          grid[at(tx, ty)] = EMPTY;
          if (rnd() < 0.35) { grid[i] = EMPTY; return; } // acid consumed
        }
      }
    }
    if (grid[i] === ACID) moveLiquid(x, y, ACID);
  }

  // --- One simulation step: bottom row up, so nothing teleports.
  function step() {
    moved.fill(0);
    for (var y = H - 1; y >= 0; y--) {
      var ltr = rnd() < 0.5;
      for (var i2 = 0; i2 < W; i2++) {
        var x = ltr ? i2 : (W - 1 - i2);
        var idx = at(x, y);
        var m = grid[idx];
        if (m === EMPTY || m === WALL || moved[idx]) continue;
        if (m === SAND) updateSand(x, y);
        else if (m === WATER) moveLiquid(x, y, WATER);
        else if (m === ACID) updateAcid(x, y);
      }
    }
  }

  // --- Rendering.
  var canvas = document.getElementById("sand");
  var ctx = canvas.getContext("2d");
  var img = ctx.createImageData(W, H);
  var BASE = [
    [12, 14, 17],     // empty
    [214, 174, 88],   // sand
    [56, 132, 214],   // water
    [138, 143, 153],  // wall
    [126, 232, 58]    // acid
  ];

  function draw() {
    var d = img.data;
    for (var i = 0; i < grid.length; i++) {
      var m = grid[i];
      var c = BASE[m];
      var n = (m === EMPTY) ? 0 : shade[i];
      var p = i * 4;
      d[p] = c[0] - n;
      d[p + 1] = c[1] - n;
      d[p + 2] = c[2] - n;
      d[p + 3] = 255;
    }
    ctx.putImageData(img, 0, 0);
  }

  // --- Public API.
  window.sim = {
    w: W,
    h: H,
    tick: function (n) {
      n = (n === undefined) ? 1 : n | 0;
      for (var i = 0; i < n; i++) step();
      draw();
    },
    get: function (x, y) {
      x |= 0; y |= 0;
      if (!inB(x, y)) return "wall";
      return NAMES[grid[at(x, y)]];
    },
    set: function (x, y, material) {
      x |= 0; y |= 0;
      if (!inB(x, y)) return;
      var id = IDS[material];
      if (id === undefined) return;
      grid[at(x, y)] = id;
      draw();
    },
    clear: function () {
      grid.fill(EMPTY);
      draw();
    }
  };

  // --- UI: material buttons.
  var current = SAND;
  var matButtons = {
    "mat-sand": SAND, "mat-water": WATER, "mat-wall": WALL,
    "mat-acid": ACID, "mat-empty": EMPTY
  };
  Object.keys(matButtons).forEach(function (id) {
    document.getElementById(id).addEventListener("click", function () {
      current = matButtons[id];
      Object.keys(matButtons).forEach(function (other) {
        document.getElementById(other).classList.toggle("active", other === id);
      });
    });
  });
  document.getElementById("clear").addEventListener("click", function () {
    window.sim.clear();
  });

  // --- Painting.
  var painting = false;
  var lastX = -1, lastY = -1;

  function cellFromEvent(e) {
    var r = canvas.getBoundingClientRect();
    return [
      Math.floor((e.clientX - r.left) / r.width * W),
      Math.floor((e.clientY - r.top) / r.height * H)
    ];
  }

  function stamp(cx, cy) {
    var radius = (current === EMPTY) ? 4 : 2;
    for (var dy = -radius; dy <= radius; dy++) {
      for (var dx = -radius; dx <= radius; dx++) {
        if (dx * dx + dy * dy > radius * radius) continue;
        var x = cx + dx, y = cy + dy;
        if (inB(x, y)) grid[at(x, y)] = current;
      }
    }
  }

  function paintLine(x0, y0, x1, y1) {
    var steps = Math.max(Math.abs(x1 - x0), Math.abs(y1 - y0), 1);
    for (var i = 0; i <= steps; i++) {
      stamp(Math.round(x0 + (x1 - x0) * i / steps),
            Math.round(y0 + (y1 - y0) * i / steps));
    }
  }

  canvas.addEventListener("pointerdown", function (e) {
    e.preventDefault();
    painting = true;
    canvas.setPointerCapture(e.pointerId);
    var c = cellFromEvent(e);
    lastX = c[0]; lastY = c[1];
    stamp(c[0], c[1]);
    draw();
  });
  canvas.addEventListener("pointermove", function (e) {
    if (!painting) return;
    var c = cellFromEvent(e);
    paintLine(lastX, lastY, c[0], c[1]);
    lastX = c[0]; lastY = c[1];
    draw();
  });
  window.addEventListener("pointerup", function () { painting = false; });

  // --- Animation loop.
  function frame() {
    step();
    draw();
    requestAnimationFrame(frame);
  }
  draw();
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
